async function initDapp() {
  const connectBtn = getEl("connectBtn");
  const loadBtn = getEl("loadContractBtn");
  const callBtn = getEl("callBtn");
  const sendBtn = getEl("sendBtn");
  const estimateBtn = getEl("estimateBtn");
  const refreshBtn = getEl("refreshBtn");

  if (connectBtn) connectBtn.addEventListener("click", connectWallet);
  if (loadBtn) loadBtn.addEventListener("click", loadContract);
  if (callBtn) callBtn.addEventListener("click", callContractMethod);
  if (sendBtn) sendBtn.addEventListener("click", sendContractTransaction);
  if (estimateBtn) estimateBtn.addEventListener("click", estimateContractTransaction);
  if (refreshBtn) refreshBtn.addEventListener("click", refreshChainInfo);

  if (window.ethereum) {
    window.ethereum.on?.("accountsChanged", async () => {
      try {
        await connectWallet();
        if (state.contract) await loadContract();
      } catch {}
    });
    window.ethereum.on?.("chainChanged", async () => {
      try {
        await refreshChainInfo();
        if (state.contract) await loadContract();
      } catch {}
    });
  }

  await refreshChainInfo();
}

document.addEventListener("DOMContentLoaded", initDapp);

